+    #[test]
+    fn config_boundary_quality_weight_extremes() {
+        let zero = TwoTierConfig {
+            quality_weight: 0.0,
+            ..Default::default()
+        };
+        assert!(zero.quality_weight.abs() < f64::EPSILON);
+
+        let one = TwoTierConfig {
